/// Errors that can occur during GraphQL operations
///
/// These errors are compatible with async-graphql error handling and can be
/// converted to structured HTTP responses matching the project's error fixtures.
public enum GraphQLError: Swift.Error {
    /// Error during schema execution
    ///
    /// Occurs when the GraphQL executor encounters a runtime error during query execution.
    case executionError(message: String, field0: String)
    /// Error during schema building
    ///
    /// Occurs when schema construction fails due to invalid definitions or conflicts.
    case schemaBuildError(message: String, field0: String)
    /// Error during request handling
    ///
    /// Occurs when the HTTP request cannot be properly handled or parsed.
    case requestHandlingError(message: String, field0: String)
    /// Serialization error
    ///
    /// Occurs during JSON serialization/deserialization of GraphQL values.
    case serializationError(message: String, field0: String)
    /// JSON parsing error
    ///
    /// Occurs when JSON input cannot be parsed.
    case jsonError(message: String, field0: String)
    /// GraphQL validation error
    ///
    /// Occurs when a GraphQL query fails schema validation.
    case validationError(message: String, field0: String)
    /// GraphQL parse error
    ///
    /// Occurs when the GraphQL query string cannot be parsed.
    case parseError(message: String, field0: String)
    /// Authentication error
    ///
    /// Occurs when request authentication fails.
    case authenticationError(message: String, field0: String)
    /// Authorization error
    ///
    /// Occurs when user lacks required permissions.
    case authorizationError(message: String, field0: String)
    /// Not found error
    ///
    /// Occurs when a requested resource is not found.
    case notFound(message: String, field0: String)
    /// Rate limit error
    ///
    /// Occurs when rate limit is exceeded.
    case rateLimitExceeded(message: String, field0: String)
    /// Invalid input error with validation details
    ///
    /// Occurs during input validation with detailed error information.
    case invalidInput(message: String, details: String?)
    /// Query complexity limit exceeded
    ///
    /// Occurs when a GraphQL query exceeds the configured complexity limit.
    case complexityLimitExceeded
    /// Query depth limit exceeded
    ///
    /// Occurs when a GraphQL query exceeds the configured depth limit.
    case depthLimitExceeded
    /// Internal server error
    ///
    /// Occurs when an unexpected internal error happens.
    case internalError(message: String, field0: String)
}

extension GraphQLError {
    public var statusCode: UInt16 {
        switch self {
        case .executionError(field0: _): return 0
        case .schemaBuildError(field0: _): return 0
        case .requestHandlingError(field0: _): return 0
        case .serializationError(field0: _): return 0
        case .jsonError(field0: _): return 0
        case .validationError(field0: _): return 0
        case .parseError(field0: _): return 0
        case .authenticationError(field0: _): return 0
        case .authorizationError(field0: _): return 0
        case .notFound(field0: _): return 0
        case .rateLimitExceeded(field0: _): return 0
        case .invalidInput(message: _, details: _): return 0
        case .complexityLimitExceeded: return 0
        case .depthLimitExceeded: return 0
        case .internalError(field0: _): return 0
        }
    }
}

/// Error type for schema building operations
public enum SchemaError: Swift.Error {
    /// Generic schema building error
    case buildingFailed(message: String, field0: String)
    /// Configuration validation error
    case validationError(message: String, field0: String)
    /// Complexity limit exceeded
    case complexityLimitExceeded(message: String, limit: UInt, actual: UInt)
    /// Depth limit exceeded
    case depthLimitExceeded(message: String, limit: UInt, actual: UInt)
}

